  ('elementary-814ced5a-moex-00218', 'elementary-814ced5a', 'elementary-814ced5a-moex-113-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於雙主題或多主題作品分類原則之敘述，下列何者錯誤？', '["若作品涉及多個時代，原則上應歸入其間最前的時代", "一作品中有雙主題並列，若二者份量相當，其中無較主要者，則分類時依順序在前原則處理", "一作品中討論A主題對B主題的影響，因A主題是造成影響的原因，所以分類時應歸入A主題", "作品中涉及三個以上主題，且其探討的重點是其中一項對其他主題的影響（如：聖嬰現象對氣候、雨 量、颱風的影響），則分類時應歸入造成影響的主題（此例是聖嬰現象）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:51+00:00", "source_pdf_sha1": "a0237e697abd", "answer_pdf_sha1": "6a56d286bcd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
